<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Ubuntu Desktop</title>
  <style>
    * {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
      user-select: none;
    }

    body, html {
      width: 100%;
      height: 100%;
      overflow: hidden;
      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Ubuntu, Cantarell, sans-serif;
      background: #2c001e;
      color: #f5f5f5;
    }

    /* Root Desktop */
    #desktop {
      position: relative;
      width: 100vw;
      height: 100vh;
      overflow: hidden;
      background: radial-gradient(circle at 50% 50%, #77216f 0%, #5e2750 40%, #2c001e 100%);
      display: flex;
      flex-direction: column;
    }

    /* Top Bar Panel */
    #top-bar {
      height: 28px;
      background: #111111;
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 0 12px;
      font-size: 13px;
      font-weight: 500;
      z-index: 1000;
      box-shadow: 0 1px 4px rgba(0, 0, 0, 0.4);
    }

    .panel-group {
      display: flex;
      align-items: center;
      gap: 14px;
    }

    .panel-item {
      cursor: pointer;
      padding: 2px 8px;
      border-radius: 4px;
      transition: background 0.15s;
    }

    .panel-item:hover {
      background: rgba(255, 255, 255, 0.15);
    }

    /* Workspace Area */
    #workspace {
      position: relative;
      flex: 1;
      width: 100%;
      height: calc(100vh - 28px);
      overflow: hidden;
    }

    /* Taskbar / Dock */
    #taskbar {
      position: absolute;
      top: 0;
      left: 0;
      bottom: 0;
      width: 68px;
      background: rgba(18, 18, 18, 0.85);
      backdrop-filter: blur(12px);
      border-right: 1px solid rgba(255, 255, 255, 0.08);
      display: flex;
      flex-direction: column;
      align-items: center;
      padding: 12px 0;
      gap: 14px;
      z-index: 900;
    }

    .launcher-btn {
      width: 48px;
      height: 48px;
      border-radius: 12px;
      background: rgba(255, 255, 255, 0.05);
      border: 1px solid rgba(255, 255, 255, 0.1);
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      transition: all 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      position: relative;
      outline: none;
    }

    .launcher-btn:hover {
      background: rgba(255, 255, 255, 0.2);
      transform: scale(1.08);
    }

    .launcher-btn:active {
      transform: scale(0.95);
    }

    .launcher-icon {
      width: 28px;
      height: 28px;
      pointer-events: none;
    }

    /* General Window Styles */
    .window {
      position: absolute;
      min-width: 360px;
      min-height: 240px;
      width: 620px;
      height: 420px;
      background: #1e1e1e;
      border-radius: 8px;
      box-shadow: 0 16px 36px rgba(0, 0, 0, 0.6), 0 0 0 1px rgba(255, 255, 255, 0.1);
      display: flex;
      flex-direction: column;
      overflow: hidden;
      z-index: 10;
    }

    .window-header {
      height: 38px;
      background: #2a2a2a;
      border-bottom: 1px solid #363636;
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 0 12px;
      cursor: move;
    }

    .window-title {
      display: flex;
      align-items: center;
      gap: 8px;
      font-size: 13px;
      font-weight: 600;
      color: #e0e0e0;
    }

    .window-controls {
      display: flex;
      align-items: center;
      gap: 8px;
    }

    .win-close {
      width: 18px;
      height: 18px;
      border-radius: 50%;
      background: #e95420;
      border: none;
      color: #ffffff;
      display: flex;
      align-items: center;
      justify-content: center;
      cursor: pointer;
      font-size: 12px;
      font-weight: bold;
      line-height: 1;
      outline: none;
      transition: background 0.15s;
    }

    .win-close:hover {
      background: #ff6b35;
    }

    .window-body {
      flex: 1;
      display: flex;
      flex-direction: column;
      overflow: hidden;
      background: #1e1e1e;
    }

    /* Common Button */
    .btn {
      background: #333333;
      color: #f0f0f0;
      border: 1px solid #444444;
      padding: 6px 12px;
      border-radius: 5px;
      font-size: 13px;
      cursor: pointer;
      display: inline-flex;
      align-items: center;
      gap: 6px;
      outline: none;
      transition: background 0.15s;
    }

    .btn:hover {
      background: #444444;
    }

    .btn:active {
      background: #2a2a2a;
    }

    /* Files App */
    .files-toolbar {
      display: flex;
      align-items: center;
      gap: 10px;
      padding: 8px 12px;
      background: #282828;
      border-bottom: 1px solid #333333;
    }

    #files-path {
      flex: 1;
      background: #141414;
      color: #e0e0e0;
      padding: 6px 12px;
      border-radius: 5px;
      border: 1px solid #333333;
      font-family: monospace;
      font-size: 13px;
      user-select: text;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }

    #files-list {
      flex: 1;
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
      grid-auto-rows: max-content;
      gap: 16px;
      padding: 16px;
      overflow-y: auto;
      background: #1e1e1e;
    }

    .fs-item {
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      padding: 10px 8px;
      border-radius: 6px;
      cursor: pointer;
      color: #e0e0e0;
      font-size: 13px;
      text-align: center;
      word-break: break-word;
      transition: background 0.15s;
      border: 1px solid transparent;
    }

    .fs-item:hover {
      background: rgba(255, 255, 255, 0.08);
    }

    .fs-item.selected {
      background: rgba(233, 84, 32, 0.25);
      border-color: #e95420;
    }

    .fs-item[data-type="dir"]::before {
      content: "📁";
      font-size: 36px;
      margin-bottom: 6px;
      display: block;
    }

    .fs-item[data-type="file"]::before {
      content: "📄";
      font-size: 36px;
      margin-bottom: 6px;
      display: block;
    }

    /* Notepad App */
    .notepad-bar {
      display: flex;
      align-items: center;
      background: #252525;
      border-bottom: 1px solid #333333;
      padding: 6px 8px 0 8px;
      gap: 8px;
    }

    #tabs {
      display: flex;
      gap: 4px;
      overflow-x: auto;
      flex: 1;
      scrollbar-width: none;
    }

    #tabs::-webkit-scrollbar {
      display: none;
    }

    .tab {
      display: flex;
      align-items: center;
      gap: 8px;
      background: #2e2e2e;
      color: #aaaaaa;
      padding: 6px 12px;
      border-radius: 6px 6px 0 0;
      font-size: 13px;
      cursor: pointer;
      border: 1px solid transparent;
      border-bottom: none;
      max-width: 180px;
      transition: background 0.15s;
    }

    .tab:hover {
      background: #383838;
      color: #e0e0e0;
    }

    .tab.active {
      background: #181818;
      color: #ffffff;
      border-color: #383838;
      border-top: 2px solid #e95420;
    }

    .tab-title {
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
      user-select: none;
    }

    .tab-close {
      font-size: 14px;
      line-height: 1;
      color: #888;
      border-radius: 50%;
      width: 16px;
      height: 16px;
      display: inline-flex;
      align-items: center;
      justify-content: center;
      transition: all 0.15s;
    }

    .tab-close:hover {
      background: rgba(255, 255, 255, 0.2);
      color: #fff;
    }

    #new-tab {
      background: transparent;
      border: none;
      color: #aaa;
      font-size: 18px;
      width: 28px;
      height: 28px;
      border-radius: 4px;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      outline: none;
      transition: background 0.15s, color 0.15s;
    }

    #new-tab:hover {
      background: rgba(255, 255, 255, 0.1);
      color: #ffffff;
    }

    #editor {
      flex: 1;
      width: 100%;
      background: #181818;
      color: #f0f0f0;
      border: none;
      outline: none;
      padding: 14px;
      font-family: monospace;
      font-size: 14px;
      line-height: 1.5;
      resize: none;
      user-select: text;
    }
  </style>
</head>
<body>

<div id="desktop">
  <!-- Top Bar -->
  <div id="top-bar">
    <div class="panel-group">
      <span class="panel-item">Activities</span>
    </div>
    <div class="panel-group">
      <span id="clock" class="panel-item">Wed 10:00 AM</span>
    </div>
    <div class="panel-group">
      <span class="panel-item">📶</span>
      <span class="panel-item">🔊</span>
      <span class="panel-item">🔋</span>
    </div>
  </div>

  <div id="workspace">
    <!-- Taskbar / Dock -->
    <div id="taskbar">
      <button id="open-files" class="launcher-btn" title="Files">
        <svg class="launcher-icon" viewBox="0 0 24 24" fill="#e95420">
          <path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/>
        </svg>
      </button>

      <button id="open-notepad" class="launcher-btn" title="Text Editor">
        <svg class="launcher-icon" viewBox="0 0 24 24" fill="#4a90e2">
          <path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-5V3.5L18.5 9H13z"/>
        </svg>
      </button>
    </div>

    <!-- Files App Window -->
    <div id="files-window" class="window" style="display: none; left: 100px; top: 50px;">
      <div class="window-header">
        <div class="window-title">
          <span>📁</span>
          <span>Files</span>
        </div>
        <div class="window-controls">
          <button class="win-close" title="Close">×</button>
        </div>
      </div>
      <div class="window-body">
        <div class="files-toolbar">
          <button id="files-up" class="btn">&uarr; Up</button>
          <div id="files-path">/</div>
        </div>
        <div id="files-list"></div>
      </div>
    </div>

    <!-- Notepad App Window -->
    <div id="notepad-window" class="window" style="display: none; left: 180px; top: 90px;">
      <div class="window-header">
        <div class="window-title">
          <span>📝</span>
          <span>Text Editor</span>
        </div>
        <div class="window-controls">
          <button class="win-close" title="Close">×</button>
        </div>
      </div>
      <div class="window-body">
        <div class="notepad-bar">
          <div id="tabs"></div>
          <button id="new-tab" title="New Tab">+</button>
        </div>
        <textarea id="editor" placeholder="Type text here..." spellcheck="false"></textarea>
      </div>
    </div>
  </div>
</div>

<script>
  // Top bar Clock
  function updateClock() {
    const clockEl = document.getElementById('clock');
    if (clockEl) {
      const now = new Date();
      clockEl.textContent = now.toLocaleString('en-US', {
        weekday: 'short',
        month: 'short',
        day: 'numeric',
        hour: 'numeric',
        minute: '2-digit'
      });
    }
  }
  setInterval(updateClock, 1000);
  updateClock();

  // Window Management & Dragging
  let topZIndex = 10;

  function bringToFront(win) {
    topZIndex++;
    win.style.zIndex = topZIndex;
  }

  document.querySelectorAll('.window').forEach(win => {
    win.addEventListener('mousedown', () => bringToFront(win));

    const header = win.querySelector('.window-header');
    let isDragging = false;
    let startX, startY, startLeft, startTop;

    header.addEventListener('mousedown', (e) => {
      if (e.target.closest('.win-close')) return;
      isDragging = true;
      startX = e.clientX;
      startY = e.clientY;
      const rect = win.getBoundingClientRect();
      startLeft = rect.left;
      startTop = rect.top;

      const onMouseMove = (moveEvent) => {
        if (!isDragging) return;
        const dx = moveEvent.clientX - startX;
        const dy = moveEvent.clientY - startY;
        win.style.left = Math.max(0, startLeft + dx) + 'px';
        win.style.top = Math.max(28, startTop + dy) + 'px';
      };

      const onMouseUp = () => {
        isDragging = false;
        document.removeEventListener('mousemove', onMouseMove);
        document.removeEventListener('mouseup', onMouseUp);
      };

      document.addEventListener('mousemove', onMouseMove);
      document.addEventListener('mouseup', onMouseUp);
    });
  });

  // Launcher Controls
  document.getElementById('open-files').addEventListener('click', () => {
    const win = document.getElementById('files-window');
    win.style.display = 'flex';
    bringToFront(win);
  });

  document.getElementById('open-notepad').addEventListener('click', () => {
    const win = document.getElementById('notepad-window');
    win.style.display = 'flex';
    bringToFront(win);
  });

  document.querySelectorAll('.win-close').forEach(btn => {
    btn.addEventListener('click', (e) => {
      const win = btn.closest('.window');
      if (win) {
        win.style.display = 'none';
      }
    });
  });

  // Files App Implementation
  const fsData = {
    '/': [
      { name: 'bin', type: 'dir' },
      { name: 'etc', type: 'dir' },
      { name: 'home', type: 'dir' },
      { name: 'usr', type: 'dir' },
      { name: 'var', type: 'dir' }
    ],
    '/bin': [
      { name: 'bash', type: 'file' },
      { name: 'cat', type: 'file' },
      { name: 'ls', type: 'file' },
      { name: 'sh', type: 'file' }
    ],
    '/etc': [
      { name: 'fstab', type: 'file' },
      { name: 'hostname', type: 'file' },
      { name: 'hosts', type: 'file' }
    ],
    '/home': [
      { name: 'user', type: 'dir' }
    ],
    '/home/user': [
      { name: 'Documents', type: 'dir' },
      { name: 'Downloads', type: 'dir' },
      { name: 'Pictures', type: 'dir' },
      { name: 'Desktop', type: 'dir' },
      { name: 'welcome.txt', type: 'file' }
    ],
    '/home/user/Documents': [
      { name: 'Project_Report.pdf', type: 'file' },
      { name: 'Notes.txt', type: 'file' }
    ],
    '/home/user/Downloads': [
      { name: 'ubuntu-24.04.iso', type: 'file' }
    ],
    '/home/user/Pictures': [
      { name: 'wallpaper.png', type: 'file' },
      { name: 'photo.jpg', type: 'file' }
    ],
    '/usr': [
      { name: 'bin', type: 'dir' },
      { name: 'lib', type: 'dir' },
      { name: 'share', type: 'dir' }
    ],
    '/usr/bin': [
      { name: 'gcc', type: 'file' },
      { name: 'python3', type: 'file' }
    ],
    '/var': [
      { name: 'log', type: 'dir' },
      { name: 'tmp', type: 'dir' }
    ],
    '/var/log': [
      { name: 'syslog', type: 'file' },
      { name: 'auth.log', type: 'file' }
    ]
  };

  let currentPath = '/';

  function renderFiles() {
    const pathEl = document.getElementById('files-path');
    const container = document.getElementById('files-list');

    pathEl.textContent = currentPath;
    container.innerHTML = '';

    const items = fsData[currentPath] || [];

    items.forEach(item => {
      const itemEl = document.createElement('div');
      itemEl.className = 'fs-item';
      itemEl.dataset.type = item.type;
      itemEl.textContent = item.name;

      itemEl.addEventListener('click', () => {
        container.querySelectorAll('.fs-item').forEach(el => el.classList.remove('selected'));
        itemEl.classList.add('selected');
      });

      itemEl.addEventListener('dblclick', () => {
        if (item.type === 'dir') {
          const nextPath = currentPath === '/' ? '/' + item.name : currentPath + '/' + item.name;
          if (!fsData[nextPath]) {
            fsData[nextPath] = [];
          }
          currentPath = nextPath;
          renderFiles();
        }
      });

      container.appendChild(itemEl);
    });
  }

  document.getElementById('files-up').addEventListener('click', () => {
    if (currentPath === '/') return;
    const parts = currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath = parts.length === 0 ? '/' : '/' + parts.join('/');
    renderFiles();
  });

  renderFiles();

  // Notepad App Implementation
  const STORAGE_KEY = 'ubuntu_notepad_data_v2';

  let notepadState = {
    tabs: [],
    activeId: null
  };

  function loadNotepad() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const parsed = JSON.parse(raw);
        if (Array.isArray(parsed.tabs) && parsed.tabs.length > 0) {
          notepadState.tabs = parsed.tabs;
          notepadState.activeId = parsed.activeId || parsed.tabs[0].id;
          return;
        }
      }
    } catch (e) {
      console.error(e);
    }

    notepadState = {
      tabs: [
        { id: 'tab_1', title: 'Untitled 1', content: 'Welcome to Text Editor!' }
      ],
      activeId: 'tab_1'
    };
    saveNotepad();
  }

  function saveNotepad() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(notepadState));
    } catch (e) {
      console.error(e);
    }
  }

  function renderNotepad() {
    const tabsContainer = document.getElementById('tabs');
    const editor = document.getElementById('editor');

    tabsContainer.innerHTML = '';

    let activeTab = notepadState.tabs.find(t => t.id === notepadState.activeId);
    if (!activeTab && notepadState.tabs.length > 0) {
      activeTab = notepadState.tabs[0];
      notepadState.activeId = activeTab.id;
    }

    notepadState.tabs.forEach(tab => {
      const tabEl = document.createElement('div');
      tabEl.className = 'tab' + (tab.id === notepadState.activeId ? ' active' : '');
      tabEl.dataset.id = tab.id;

      const titleSpan = document.createElement('span');
      titleSpan.className = 'tab-title';
      titleSpan.textContent = tab.title;
      tabEl.appendChild(titleSpan);

      const closeBtn = document.createElement('span');
      closeBtn.className = 'tab-close';
      closeBtn.innerHTML = '&times;';
      closeBtn.title = 'Close tab';
      closeBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        closeTab(tab.id);
      });
      tabEl.appendChild(closeBtn);

      tabEl.addEventListener('click', () => {
        notepadState.activeId = tab.id;
        saveNotepad();
        renderNotepad();
      });

      tabsContainer.appendChild(tabEl);
    });

    if (activeTab) {
      editor.value = activeTab.content;
      editor.disabled = false;
    } else {
      editor.value = '';
      editor.disabled = true;
    }
  }

  function closeTab(id) {
    const idx = notepadState.tabs.findIndex(t => t.id === id);
    if (idx !== -1) {
      notepadState.tabs.splice(idx, 1);
      if (notepadState.tabs.length === 0) {
        const newTab = { id: 'tab_' + Date.now(), title: 'Untitled 1', content: '' };
        notepadState.tabs.push(newTab);
        notepadState.activeId = newTab.id;
      } else if (notepadState.activeId === id) {
        notepadState.activeId = notepadState.tabs[Math.max(0, idx - 1)].id;
      }
      saveNotepad();
      renderNotepad();
    }
  }

  document.getElementById('new-tab').addEventListener('click', () => {
    const newId = 'tab_' + Date.now();
    const count = notepadState.tabs.length + 1;
    const newTab = {
      id: newId,
      title: 'Untitled ' + count,
      content: ''
    };
    notepadState.tabs.push(newTab);
    notepadState.activeId = newId;
    saveNotepad();
    renderNotepad();
    document.getElementById('editor').focus();
  });

  document.getElementById('editor').addEventListener('input', (e) => {
    const activeTab = notepadState.tabs.find(t => t.id === notepadState.activeId);
    if (activeTab) {
      activeTab.content = e.target.value;
      saveNotepad();
    }
  });

  loadNotepad();
  renderNotepad();
</script>

</body>
</html>
